// 1. Fetch raw data from the 'Get an Issue' node
const fields = $input.item.json.fields || {};
const summary = fields.summary || "";

// 2. Check for Keyword Matches in Summary & Assign custom Diagnosis
const lowerSummary = summary.toLowerCase();
let mappedDiagnosis = null;

if (
  lowerSummary.includes("meminfo") || 
  lowerSummary.includes("ssh meminfo") || 
  lowerSummary.includes("physical memory")
) {
  mappedDiagnosis = "High Memory Utilization";
} else if (lowerSummary.includes("disks") || lowerSummary.includes("disk")) {
  mappedDiagnosis = "Disk Utilization";
} else if (lowerSummary.includes("cpu") || lowerSummary.includes("cpu load")) {
  mappedDiagnosis = "High CPU Utilization";
} else if (
  lowerSummary.includes("http") || 
  lowerSummary.includes("https") || 
  lowerSummary.includes("web api") || 
  lowerSummary.includes("api")
) {
  mappedDiagnosis = "HTTP Downtime";
}

// CRITICAL FILTER: Drop unrelated tickets instantly
if (!mappedDiagnosis) {
  return []; 
}

// 3. Extract Core Fields
const desc = fields.description || "";
const key = $input.item.json.key || "";
const status = fields.status?.name || "";
const assigneeName = fields.assignee?.displayName || "Unassigned";

// 4. Extract Description Details via Regex
const startOfDowntimeMatch = desc.match(/as of\s+([\d/: ]+\s*(?:AM|PM)?)/i);
const dateMatch = desc.match(/\d{1,2}\/\d{1,2}\/\d{4}/);

let serverDevice = null;
const serverDeviceMatch = desc.match(/The\s+([\s\S]*?)\s+usage/i);
if (serverDeviceMatch) {
  serverDevice = serverDeviceMatch[1].trim();
} else {
  const firstLine = desc.split('\n')[0] || "";
  serverDevice = firstLine.length > 50 ? "Web Service/API" : firstLine.trim() || "HTTP Endpoint";
}

const serverIdMatch = desc.match(/sensor\.htm\?id=(\d+)/);

// 5. ANTI-BOT COMMENT SCANNER (Super Flexible Regex Matching)
const comments = fields.comment?.comments || [];
let latestCommentText = "";
let latestCommentAuthor = "";
let timeRestoredStr = null;

for (let i = comments.length - 1; i >= 0; i--) {
  const authorName = comments[i].author?.displayName || "";
  const currentCommentText = comments[i].body || "";

  if (authorName.toLowerCase().includes("automation")) {
    continue; 
  }

  // FLEXIBLE REGEX: Captures dates like M/D/YYYY followed by any time string and optional AM/PM
  const flexibleMatch = currentCommentText.match(/\d{1,2}\/\d{1,2}\/\d{4}\s+\d{1,2}:\d{2}(?::\d{2})?\s*(?:AM|PM)?/i);

  if (flexibleMatch) {
    timeRestoredStr = flexibleMatch[0];
    latestCommentText = currentCommentText;
    latestCommentAuthor = authorName;
    break; 
  }
}

// 6. ULTRA-FLEXIBLE DATE PARSER
function parseAnything(dateStr) {
  if (!dateStr) return null;

  // Clean extra spaces
  const cleanStr = dateStr.trim().replace(/\s+/g, ' ');

  // Extract date component and time component
  const parts = cleanStr.split(' ');
  const dateParts = parts[0].split('/');
  if (dateParts.length !== 3) return null;

  const month = parseInt(dateParts[0], 10) - 1;
  const day = parseInt(dateParts[1], 10);
  const year = parseInt(dateParts[2], 10);

  // Default time fallbacks
  let hours = 0, minutes = 0, seconds = 0;

  if (parts[1]) {
    const timeParts = parts[1].split(':');
    hours = parseInt(timeParts[0], 10) || 0;
    minutes = parseInt(timeParts[1], 10) || 0;
    seconds = parseInt(timeParts[2], 10) || 0;
  }

  // Check for AM/PM modifiers anywhere in the string
  const upperStr = cleanStr.toUpperCase();
  const isPM = upperStr.includes('PM');
  const isAM = upperStr.includes('AM');

  if (isPM && hours < 12) hours += 12;
  if (isAM && hours === 12) hours = 0;

  const generatedDate = new Date(year, month, day, hours, minutes, seconds);
  return isNaN(generatedDate.getTime()) ? null : generatedDate;
}

// 7. Compute Total Downtime Duration
let formattedTotalDowntime = "";
if (startOfDowntimeMatch && timeRestoredStr) {
  const startCommenced = parseAnything(startOfDowntimeMatch[1]);
  const endRestored = parseAnything(timeRestoredStr);

  if (startCommenced && endRestored) {
    const diffMs = endRestored - startCommenced;
    if (diffMs > 0) {
      const totalMinutes = Math.floor(diffMs / 1000 / 60);
      const hours = Math.floor(totalMinutes / 60);
      const minutes = totalMinutes % 60;

      if (hours > 0) {
        formattedTotalDowntime = `${hours}Hours, ${minutes} Mins`;
      } else {
        formattedTotalDowntime = `${minutes}Mins`;
      }
    } else {
      formattedTotalDowntime = "0Mins";
    }
  }
}

// 8. Dynamically Generate Target Sheet Name
let targetSheetName = "";
const targetDateStr = dateMatch ? dateMatch[0] : startOfDowntimeMatch ? startOfDowntimeMatch[1].split(' ')[0] : null;

if (targetDateStr && targetDateStr.includes('/')) {
  const alertDate = parseAnything(targetDateStr + " 00:00:00 AM") || new Date();
  const monthName = alertDate.toLocaleString('default', { month: 'long' });
  const year = alertDate.getFullYear();
  targetSheetName = `PRTG Critical Alerts ${monthName} ${year}`;
} else {
  const now = new Date();
  const monthName = now.toLocaleString('default', { month: 'long' });
  targetSheetName = `PRTG Critical Alerts ${monthName} ${now.getFullYear()}`;
}

return {
  json: {
    ticket_key: key,
    summary: summary,
    status: status,
    assignee_name: assigneeName,
    start_of_downtime: startOfDowntimeMatch ? startOfDowntimeMatch[1].trim() : null,
    date: dateMatch ? dateMatch[0] : (targetDateStr || null),
    server_device: serverDevice,            
    server_id: serverIdMatch ? serverIdMatch[1] : null,
    diagnosis: mappedDiagnosis,
    latest_comment: latestCommentText,
    time_restored: timeRestoredStr,            
    total_downtime: formattedTotalDowntime,  
    target_sheet_name: targetSheetName
  }
};
